async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click the item slot (slot 0)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click the equip button
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);

  // Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

