async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Use camera math to click directly on the Forester's screen position
  let attempts = 0;
  while (attempts < 8) {
    const info = await page.evaluate(() => {
      const game = window.game;
      const camera = game.camera;
      const zoom = camera.zoomFactor;
      const tileBase = 16;
      const camX = camera.x;
      const camY = camera.y;
      const s = window.__latestGameState;
      const forester = s.nearby_entities.find(e => e.name === 'Forester');
      if (!forester) return null;
      const sx = Math.round((forester.x * tileBase - camX) * zoom);
      const sy = Math.round((forester.y * tileBase - camY) * zoom);
      return {dist: forester.distance, sx, sy, pos: s.player_position};
    });

    if (!info) break;

    if (info.dist <= 3) break; // Close enough to interact

    // Clamp to screen and click toward Forester
    const sx = Math.max(100, Math.min(1180, info.sx));
    const sy = Math.max(80, Math.min(680, info.sy));
    await click(sx, sy);
    await page.waitForTimeout(3000);
    attempts++;
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const forester = s.nearby_entities.find(e => e.name === 'Forester');
    return JSON.stringify({pos: s.player_position, foresterDist: forester?.distance});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return state;
}

